outputs.css:
:root {
  container-type: inline-size;
  container-name: viewport-width;
}

@container viewport-width (width < 768px) {
.app {
  grid-template-columns: 1fr;
}
.chat__messages {
  max-height: 45dvh;
}
}

@container viewport-width (width >= 768px) {
.app {
  grid-template-columns: minmax(0, 1fr) 22rem;
  grid-template-areas: 'chat rail'
          'timeline timeline';
}
.chat {
  grid-area: chat;
}
.rail {
  grid-area: rail;
}
.timeline {
  grid-area: timeline;
}
.chat__messages {
  max-height: 58dvh;
}
}

